static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k04600CustomTilingData tiling;

    const gert::StorageShape *xShape = context->GetInputShape(0);
    const auto &originShape = xShape->GetOriginShape();
    uint32_t totalLength = static_cast<uint32_t>(originShape.GetShapeSize());
    uint32_t numFeatures = static_cast<uint32_t>(originShape.GetDim(1));
    uint32_t spatialSize = static_cast<uint32_t>(originShape.GetDim(2)) * static_cast<uint32_t>(originShape.GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *eps = attrs->GetAttrPointer<float>(0);

    uint32_t tileLength = spatialSize;
    if (tileLength < 1024) tileLength = 1024;
    uint32_t blockDim = 16;
    if (blockDim == 0) blockDim = 8;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLength);
    tiling.set_blockDim(blockDim);
    tiling.set_eps(*eps);
    tiling.set_numFeatures(numFeatures);
    tiling.set_spatialSize(spatialSize);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

